// Read model selected from Form Trigger dropdown
const formData = $('Form Trigger').first()?.json || {};
const selectedModelLabel = String(formData['Ollama Model (Primary)'] || '');

// Extract just the model ID (before the space in the label)
const MODEL_MAP = {
  'qwen2.5:7b-instruct-q4_K_M (สมดุล - แนะนำ)': 'qwen2.5:7b-instruct-q4_K_M',
