const item = $input.first();
const binaryData = $('Read PDF File').first().binary.data;

// Fix: Override fileName to use NFC-normalized name from Excel
// Prevents encoding corruption (Thai chars appearing as Chinese)
const fileName = String(item.json.file_name || '').normalize('NFC');
const safeName = fileName.toLowerCase().endsWith('.pdf') ? fileName : fileName + '.pdf';

return {
  json: { ...item.json },
  binary: {
    data: {
      ...binaryData,
      fileName: safeName,
      mimeType: 'application/pdf'
    }
  }
};

const uploadResults = $input.all();
const config = $('Set Configuration').first().json.config;
// Original data is in Restore Binary (before Upload replaced json with HTTP response)
const originalItems = $('Restore Binary').all();

return uploadResults.map((uploadWrapper, i) => {
  const uploadResult = uploadWrapper.json;
  const item = originalItems[i]?.json || {};
  const ai = item.ai_result || {};

  return {
    json: {
      ...item,
      enqueue_payload: {
        document_number: String(item.document_number || ''),
        subject: String(ai.subject || item.subject || ''),
        original_subject: String(item.subject || ''),
        category: ai.suggested_category || 'Correspondence',
        type_code: ai.type_code || 'LETTER',
        type_id: ai.type_id || null,
        body: String(ai.body || ai.summary || ''),
        ai_summary: ai.summary || ai.body || '',
        project_id: Number(ai.project_id || config.PROJECT_ID),
        sender_org_id: ai.sender_id || null,
        receiver_org_id: ai.receiver_id || null,
        issued_date: ai.issued_date || item.issued_date || '',
        received_date: ai.received_date || item.received_date || '',
        remarks: item.remarks ? item.remarks + (item.staging_remarks ? ' [System: ' + item.staging_remarks + ']' : '') : (item.staging_remarks || ''),
        extracted_tags: ai.tags || [],
        details: { tags: ai.tags || [] },
        temp_attachment_id: uploadResult.id || uploadResult.tempId || null,
        is_valid: ai.is_valid !== false,
        confidence: ai.confidence || 0.0,
        ai_issues: ai.key_points || [],
        ai_empty: ai.ai_empty || false
      }
    }
  };
});
